"""
Master Kit Reference Kit Investigation - Backend Testing
Investigating the critical issue with "Select Master Kit" field not pulling data from database during Reference Kit creation.

Issue: The "Select Master Kit" field in the Reference Kit creation form is not showing any master kits from the database.
User Context: User mentioned there's a Paris Saint-Germain master kit that's "pending validation" which might be why it's not appearing.

Requirements:
1. Check if there are master kits in the database and their verification status
2. Investigate why the GET /api/master-kits endpoint might not be returning data for the frontend form
3. Implement auto-approval for testing purposes - automatically approve any additions to database (teams, brands, players, leagues, master kits)
4. Test the complete workflow: check master kits exist → ensure they can be retrieved → verify they appear in Reference Kit creation form

Authentication: Use admin credentials topkitfr@gmail.com / TopKitSecure789#
"""

import requests
import json
import sys
import base64
from datetime import datetime
from typing import Dict, Any, List, Optional

# Configuration
BACKEND_URL = "https://topkit-workflow-fix.preview.emergentagent.com/api"

# Test credentials
ADMIN_EMAIL = "topkitfr@gmail.com"
ADMIN_PASSWORD = "TopKitSecure789#"

class MasterKitReferenceKitInvestigator:
    def __init__(self):
        self.session = requests.Session()
        self.admin_token = None
        self.admin_user_id = None
        self.test_results = []
        
    def log_result(self, test_name: str, success: bool, message: str, details: Dict = None):
        """Log test result"""
        result = {
            "test": test_name,
            "success": success,
            "message": message,
            "details": details or {},
            "timestamp": datetime.now().isoformat()
        }
        self.test_results.append(result)
        status = "✅ PASS" if success else "❌ FAIL"
        print(f"{status}: {test_name} - {message}")
        if details and len(str(details)) < 500:  # Only print short details
            print(f"   Details: {json.dumps(details, indent=2)}")
    
    def authenticate_admin(self) -> bool:
        """Authenticate as admin user"""
        try:
            response = self.session.post(f"{BACKEND_URL}/auth/login", json={
                "email": ADMIN_EMAIL,
                "password": ADMIN_PASSWORD
            })
            
            if response.status_code == 200:
                data = response.json()
                self.admin_token = data.get("token")
                self.admin_user_id = data.get("user", {}).get("id")
                
                # Set authorization header for future requests
                self.session.headers.update({
                    "Authorization": f"Bearer {self.admin_token}"
                })
                
                self.log_result(
                    "Admin Authentication", 
                    True, 
                    f"Successfully authenticated as admin: {data.get('user', {}).get('name', 'Unknown')}", 
                    {
                        "user_id": self.admin_user_id,
                        "role": data.get("user", {}).get("role"),
                        "token_length": len(self.admin_token) if self.admin_token else 0
                    }
                )
                return True
            else:
                self.log_result(
                    "Admin Authentication", 
                    False, 
                    f"Authentication failed: {response.status_code}", 
                    {"response": response.text}
                )
                return False
                
        except Exception as e:
            self.log_result("Admin Authentication", False, f"Authentication error: {str(e)}")
            return False
    
    def check_master_kits_in_database(self) -> Dict[str, Any]:
        """Check if master kits exist in database and their verification status"""
        try:
            response = self.session.get(f"{BACKEND_URL}/master-kits")
            
            if response.status_code == 200:
                master_kits = response.json()
                
                # Analyze master kits
                total_count = len(master_kits)
                psg_kits = [kit for kit in master_kits if 'paris' in kit.get('team_info', {}).get('name', '').lower() or 'psg' in kit.get('team_info', {}).get('name', '').lower()]
                pending_kits = [kit for kit in master_kits if kit.get('status') == 'pending']
                approved_kits = [kit for kit in master_kits if kit.get('status') == 'approved']
                
                analysis = {
                    "total_master_kits": total_count,
                    "psg_master_kits": len(psg_kits),
                    "pending_master_kits": len(pending_kits),
                    "approved_master_kits": len(approved_kits),
                    "psg_kits_details": psg_kits[:3],  # First 3 PSG kits for analysis
                    "pending_kits_details": pending_kits[:3],  # First 3 pending kits
                    "sample_master_kits": master_kits[:3] if master_kits else []
                }
                
                self.log_result(
                    "Master Kits Database Check", 
                    True, 
                    f"Found {total_count} master kits in database. PSG kits: {len(psg_kits)}, Pending: {len(pending_kits)}, Approved: {len(approved_kits)}", 
                    analysis
                )
                return analysis
            else:
                self.log_result(
                    "Master Kits Database Check", 
                    False, 
                    f"Failed to retrieve master kits: {response.status_code}", 
                    {"response": response.text}
                )
                return {}
                
        except Exception as e:
            self.log_result("Master Kits Database Check", False, f"Error checking master kits: {str(e)}")
            return {}
    
    def test_master_kits_endpoint_filtering(self) -> Dict[str, Any]:
        """Test master kits endpoint with various filtering options"""
        try:
            results = {}
            
            # Test 1: Get all master kits
            response = self.session.get(f"{BACKEND_URL}/master-kits")
            if response.status_code == 200:
                all_kits = response.json()
                results["all_kits"] = {
                    "count": len(all_kits),
                    "sample": all_kits[:2] if all_kits else []
                }
            
            # Test 2: Get master kits by team (if we have teams)
            teams_response = self.session.get(f"{BACKEND_URL}/teams")
            if teams_response.status_code == 200:
                teams = teams_response.json()
                if teams:
                    # Test with first team
                    team_id = teams[0].get('id')
                    team_name = teams[0].get('name', 'Unknown')
                    
                    response = self.session.get(f"{BACKEND_URL}/master-kits?team_id={team_id}")
                    if response.status_code == 200:
                        team_kits = response.json()
                        results["team_filtered_kits"] = {
                            "team_name": team_name,
                            "team_id": team_id,
                            "count": len(team_kits),
                            "kits": team_kits
                        }
            
            # Test 3: Check for PSG specifically
            psg_teams = [team for team in teams if 'paris' in team.get('name', '').lower() or 'psg' in team.get('name', '').lower()]
            if psg_teams:
                psg_team = psg_teams[0]
                response = self.session.get(f"{BACKEND_URL}/master-kits?team_id={psg_team['id']}")
                if response.status_code == 200:
                    psg_kits = response.json()
                    results["psg_kits"] = {
                        "team_name": psg_team.get('name'),
                        "team_id": psg_team.get('id'),
                        "count": len(psg_kits),
                        "kits": psg_kits,
                        "status_breakdown": {}
                    }
                    
                    # Analyze status breakdown
                    for kit in psg_kits:
                        status = kit.get('status', 'unknown')
                        results["psg_kits"]["status_breakdown"][status] = results["psg_kits"]["status_breakdown"].get(status, 0) + 1
            
            success = len(results) > 0
            message = f"Master kits endpoint testing completed. Found {len(results)} test scenarios."
            
            self.log_result("Master Kits Endpoint Filtering", success, message, results)
            return results
            
        except Exception as e:
            self.log_result("Master Kits Endpoint Filtering", False, f"Error testing endpoints: {str(e)}")
            return {}
    
    def check_reference_kit_creation_dependencies(self) -> Dict[str, Any]:
        """Check all dependencies needed for Reference Kit creation"""
        try:
            dependencies = {}
            
            # Check teams
            response = self.session.get(f"{BACKEND_URL}/teams")
            if response.status_code == 200:
                teams = response.json()
                dependencies["teams"] = {
                    "count": len(teams),
                    "available": len(teams) > 0,
                    "sample": teams[:3] if teams else []
                }
            
            # Check competitions
            response = self.session.get(f"{BACKEND_URL}/competitions")
            if response.status_code == 200:
                competitions = response.json()
                dependencies["competitions"] = {
                    "count": len(competitions),
                    "available": len(competitions) > 0,
                    "sample": competitions[:3] if competitions else []
                }
            
            # Check master kits
            response = self.session.get(f"{BACKEND_URL}/master-kits")
            if response.status_code == 200:
                master_kits = response.json()
                dependencies["master_kits"] = {
                    "count": len(master_kits),
                    "available": len(master_kits) > 0,
                    "approved_count": len([kit for kit in master_kits if kit.get('status') == 'approved']),
                    "pending_count": len([kit for kit in master_kits if kit.get('status') == 'pending']),
                    "sample": master_kits[:3] if master_kits else []
                }
            
            # Check form dependencies endpoint
            response = self.session.get(f"{BACKEND_URL}/form-dependencies/teams-by-competition/1")
            dependencies["form_dependencies_working"] = response.status_code == 200
            
            all_available = all(dep.get("available", False) for dep in dependencies.values() if isinstance(dep, dict))
            
            self.log_result(
                "Reference Kit Creation Dependencies", 
                all_available, 
                f"Dependencies check: Teams({dependencies.get('teams', {}).get('count', 0)}), Competitions({dependencies.get('competitions', {}).get('count', 0)}), Master Kits({dependencies.get('master_kits', {}).get('count', 0)})", 
                dependencies
            )
            return dependencies
            
        except Exception as e:
            self.log_result("Reference Kit Creation Dependencies", False, f"Error checking dependencies: {str(e)}")
            return {}
    
    def auto_approve_pending_master_kits(self) -> Dict[str, Any]:
        """Auto-approve any pending master kits for testing purposes"""
        try:
            # Get all master kits
            response = self.session.get(f"{BACKEND_URL}/master-kits")
            if response.status_code != 200:
                self.log_result("Auto-Approve Master Kits", False, "Could not retrieve master kits for approval")
                return {}
            
            master_kits = response.json()
            pending_kits = [kit for kit in master_kits if kit.get('status') == 'pending']
            
            if not pending_kits:
                self.log_result("Auto-Approve Master Kits", True, "No pending master kits found - all already approved")
                return {"approved_count": 0, "already_approved": len(master_kits)}
            
            approved_count = 0
            approval_results = []
            
            # Try to approve each pending kit
            for kit in pending_kits:
                kit_id = kit.get('id')
                if not kit_id:
                    continue
                
                # Try different approval endpoints
                approval_endpoints = [
                    f"{BACKEND_URL}/master-kits/{kit_id}/approve",
                    f"{BACKEND_URL}/master-jerseys/{kit_id}/approve",
                    f"{BACKEND_URL}/admin/master-kits/{kit_id}/approve"
                ]
                
                approved = False
                for endpoint in approval_endpoints:
                    try:
                        response = self.session.post(endpoint, json={"status": "approved"})
                        if response.status_code in [200, 201]:
                            approved = True
                            approved_count += 1
                            approval_results.append({
                                "kit_id": kit_id,
                                "team": kit.get('team_info', {}).get('name', 'Unknown'),
                                "endpoint_used": endpoint,
                                "success": True
                            })
                            break
                    except:
                        continue
                
                if not approved:
                    # Try PATCH method
                    try:
                        response = self.session.patch(f"{BACKEND_URL}/master-kits/{kit_id}", json={"status": "approved"})
                        if response.status_code in [200, 201]:
                            approved = True
                            approved_count += 1
                            approval_results.append({
                                "kit_id": kit_id,
                                "team": kit.get('team_info', {}).get('name', 'Unknown'),
                                "method": "PATCH",
                                "success": True
                            })
                    except:
                        approval_results.append({
                            "kit_id": kit_id,
                            "team": kit.get('team_info', {}).get('name', 'Unknown'),
                            "success": False,
                            "error": "No working approval endpoint found"
                        })
            
            result_data = {
                "total_pending": len(pending_kits),
                "approved_count": approved_count,
                "approval_results": approval_results
            }
            
            success = approved_count > 0 or len(pending_kits) == 0
            message = f"Auto-approval completed: {approved_count}/{len(pending_kits)} master kits approved"
            
            self.log_result("Auto-Approve Master Kits", success, message, result_data)
            return result_data
            
        except Exception as e:
            self.log_result("Auto-Approve Master Kits", False, f"Error during auto-approval: {str(e)}")
            return {}
    
    def test_reference_kit_creation_workflow(self) -> Dict[str, Any]:
        """Test the complete Reference Kit creation workflow"""
        try:
            # Step 1: Get teams for selection
            teams_response = self.session.get(f"{BACKEND_URL}/teams")
            if teams_response.status_code != 200:
                self.log_result("Reference Kit Creation Workflow", False, "Cannot retrieve teams for workflow")
                return {}
            
            teams = teams_response.json()
            if not teams:
                self.log_result("Reference Kit Creation Workflow", False, "No teams available for workflow")
                return {}
            
            # Step 2: Select a team (prefer PSG if available)
            selected_team = None
            for team in teams:
                if 'paris' in team.get('name', '').lower() or 'psg' in team.get('name', '').lower():
                    selected_team = team
                    break
            
            if not selected_team:
                selected_team = teams[0]  # Use first available team
            
            # Step 3: Get master kits for selected team
            master_kits_response = self.session.get(f"{BACKEND_URL}/master-kits?team_id={selected_team['id']}")
            if master_kits_response.status_code != 200:
                self.log_result("Reference Kit Creation Workflow", False, f"Cannot retrieve master kits for team {selected_team.get('name')}")
                return {}
            
            team_master_kits = master_kits_response.json()
            if not team_master_kits:
                self.log_result("Reference Kit Creation Workflow", False, f"No master kits found for team {selected_team.get('name')} - this is the root cause of the issue!")
                return {
                    "issue_identified": True,
                    "root_cause": f"No master kits available for team {selected_team.get('name')}",
                    "team_id": selected_team.get('id'),
                    "team_name": selected_team.get('name')
                }
            
            # Step 4: Try to create a reference kit
            selected_master_kit = team_master_kits[0]
            
            reference_kit_data = {
                "master_kit_id": selected_master_kit.get('id'),
                "competition_id": "test-competition-id",  # This might need to be a real competition ID
                "model": "replica",
                "limited_edition": False,
                "sku_code": f"REF-{datetime.now().strftime('%Y%m%d%H%M%S')}",
                "barcode": f"123456789{datetime.now().strftime('%H%M%S')}",
                "main_photo": "data:image/jpeg;base64,"
            }
            
            response = self.session.post(f"{BACKEND_URL}/reference-kits", json=reference_kit_data)
            
            workflow_result = {
                "selected_team": selected_team.get('name'),
                "team_id": selected_team.get('id'),
                "available_master_kits": len(team_master_kits),
                "selected_master_kit": selected_master_kit.get('id') if selected_master_kit else None,
                "reference_kit_creation_status": response.status_code,
                "reference_kit_creation_success": response.status_code in [200, 201],
                "workflow_complete": response.status_code in [200, 201]
            }
            
            if response.status_code in [200, 201]:
                created_kit = response.json()
                workflow_result["created_reference_kit_id"] = created_kit.get('id')
            else:
                workflow_result["creation_error"] = response.text
            
            success = workflow_result["workflow_complete"]
            message = f"Reference Kit creation workflow: {'SUCCESS' if success else 'FAILED'} - Team: {selected_team.get('name')}, Master Kits: {len(team_master_kits)}"
            
            self.log_result("Reference Kit Creation Workflow", success, message, workflow_result)
            return workflow_result
            
        except Exception as e:
            self.log_result("Reference Kit Creation Workflow", False, f"Error in workflow: {str(e)}")
            return {}
    
